import React from "react";

export default function ModalConfig({ open, close, children }) {
  if (!open) return null;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        backgroundColor: "rgba(0, 0, 0, 0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          backgroundColor: "white",
          width: "90%",
          maxWidth: "360px",
          height: "360px",
          position: "relative",
        }}
      >
        <button
          onClick={close}
          style={{ position: "absolute", top: "12px", right: "12px" }}
        >
          X
        </button>
        {children}
      </div>
    </div>
  );
}
